    {"case_name": "Bachan Singh v. State of Punjab", "citation": "AIR 1980 SC 898", "court": "Supreme Court of India", "year": 1980, "judges": ["Y.V. Chandrachud CJ", "A.C. Gupta J", "N.L. Untwalia J", "P.N. Bhagwati J", "R.S. Sarkaria J"], "facts": "Constitutional validity of the death penalty under Section 302 IPC read with Section 354(3) CrPC was challenged. The question was whether the death penalty was violative of Articles 14, 19 and 21 of the Constitution.", "held": "The death penalty is constitutionally valid but must be imposed only in the 'rarest of rare' cases where the alternative of life imprisonment is unquestionably foreclosed. The court laid down guidelines for when death penalty may be imposed.", "legal_principle": "Death penalty permissible only in 'rarest of rare' cases — a case which, when observed, the collective conscience of the community is so shocked that it expects holders of judicial power to inflict death penalty.", "relevant_sections": ["IPC 302", "CrPC 354(3)"], "keywords": ["death penalty", "rarest of rare", "capital punishment", "murder sentencing", "life imprisonment"]},
    {"case_name": "Maneka Gandhi v. Union of India", "citation": "AIR 1978 SC 597", "court": "Supreme Court of India", "year": 1978, "judges": ["M.H. Beg CJ", "Y.V. Chandrachud J", "V.R. Krishna Iyer J", "P.N. Bhagwati J", "N.L. Untwalia J", "S. Murtaza Fazal Ali J", "P.S. Kailasam J"], "facts": "Petitioner's passport was impounded by the Government without giving her any opportunity to be heard. The question was whether this violated her fundamental rights under Articles 14, 19 and 21.", "held": "The right to live is not merely confined to physical existence but includes the right to live with human dignity. The procedure established by law must be fair, just and reasonable. The three Articles 14, 19 and 21 are not mutually exclusive and must be read together.", "legal_principle": "Right to life under Article 21 includes right to live with dignity. Any law depriving life/liberty must be fair, just, and reasonable. Articles 14, 19, and 21 form a golden triangle.", "relevant_sections": ["Constitution Article 21", "Constitution Article 14", "Constitution Article 19"], "keywords": ["right to life", "personal liberty", "due process", "natural justice", "fundamental rights", "Article 21"]},
